/* モバイルファースト */
.container {
  padding: 16px;
}

/* タブレット以上 */
@media (min-width: 768px) {
  .container {
    padding: 32px;
    max-width: 720px;
    margin: 0 auto;
  }
}

/* デスクトップ */
@media (min-width: 1024px) {
  .container {
    max-width: 960px;
  }
}

/* 横向き判定 */
@media (orientation: landscape) {
  .sidebar { display: block; }
}

/* 印刷用 */
@media print {
  .no-print { display: none; }
}

/* コンテナを定義 */
.wrapper {
  container-type: inline-size;
  container-name: sidebar;
}

/* コンテナ幅に応じたスタイル */
@container sidebar (min-width: 400px) {
  .card {
    display: flex;
    flex-direction: row;
  }
}

@container sidebar (max-width: 399px) {
  .card {
    display: flex;
    flex-direction: column;
  }
}

/* コンテナクエリ単位 */
.text {
  font-size: clamp(0.875rem, 3cqi, 1.25rem);
  /* cqi = コンテナのインライン方向の1% */
}

/* CSS変数でテーマ管理 */
:root {
  --bg: #ffffff;
  --text: #1e293b;
  --border: #e2e8f0;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f172a;
    --text: #e2e8f0;
    --border: #334155;
  }
}

body {
  background: var(--bg);
  color: var(--text);
}

/* JSでの検出 */
// const isDark = window.matchMedia(
