// ).matches;

/* 流体タイポグラフィ */
h1 {
  font-size: clamp(1.5rem, 4vw, 3rem);
}
p {
  font-size: clamp(0.875rem, 1.5vw, 1.125rem);
}

/* レスポンシブな幅 */
.container {
  width: min(90%, 1200px);
  margin: 0 auto;
}

/* 余白の流体制御 */
section {
  padding: clamp(1rem, 5vw, 4rem);
}

/* max() で最低サイズを保証 */
.sidebar {
  width: max(250px, 25%);
}

/* min() で最大サイズを制限 */
.card {
  width: min(100%, 400px);
}

/* 動画コンテナ */
.video-wrapper {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: #000;
}

/* 正方形 */
.avatar {
  width: 64px;
  aspect-ratio: 1;
  border-radius: 50%;
  object-fit: cover;
}

/* カードサムネイル */
.card-image {
  width: 100%;
  aspect-ratio: 4 / 3;
  object-fit: cover;
}

/* auto: 固有アスペクト比を使用 */
img {
  aspect-ratio: auto;
  width: 100%;
  height: auto;
}

/* 従来のビューポート単位 */
.hero {
  height: 100vh;      /* ビューポートの高さ */
  width: 100vw;       /* ビューポートの幅 */
}

/* 新しいビューポート単位（モバイル対応） */
.hero-mobile {
  height: 100dvh;     /* 動的ビューポート高さ */
  /* アドレスバーの表示/非表示に追従 */
}
.hero-safe {
  min-height: 100svh; /* 最小ビューポート高さ */
  /* アドレスバー表示時の高さ */
}

/* vmin / vmax */
.square {
  width: 50vmin;      /* 幅と高さの小さい方の50% */
  height: 50vmin;
}

/* テキストサイズ */
.responsive-text {
  font-size: clamp(1rem, 3vw, 2rem);
}

const observer = new ResizeObserver((entries) => {
  for (const entry of entries) {
    const { width, height } = entry.contentRect;
    console.log(`${width} x ${height}`);

    // サイズに応じたクラス切替
    if (width < 400) {
      entry.target.classList.add('compact');
    } else {
      entry.target.classList.remove('compact');
    }
  }
});

// 監視開始
observer.observe(document.getElementById('container'));

// 複数要素を監視
document.querySelectorAll('.card').forEach(el => {
  observer.observe(el);
});

// 監視停止
observer.disconnect();

// 基本的な使い方
const mq = window.matchMedia('(min-width: 768px)');
console.log(mq.matches); // true or false

// 変更を監視
mq.addEventListener('change', (e) => {
  if (e.matches) {
    console.log('デスクトップ表示');
  } else {
    console.log('モバイル表示');
  }
});

// ダークモード検出
const darkMq = window.matchMedia(
  '(prefers-color-scheme: dark)'
);
if (darkMq.matches) {
  document.body.classList.add('dark');
}
darkMq.addEventListener('change', (e) => {
  document.body.classList.toggle('dark', e.matches);
});

// アニメーション低減検出
const motionMq = window.matchMedia(
  '(prefers-reduced-motion: reduce)'
);
